import React, { useState } from 'react'
import { CButton, CCard, CCardBody, CCardGroup, CCol, CContainer, CForm, CFormInput, CInputGroup, CInputGroupText, CRow } from '@coreui/react'
import CIcon from '@coreui/icons-react'
import { cilLockLocked, cilUser } from '@coreui/icons'
import { useNavigate } from 'react-router-dom'
import { validateEmail } from '../../utils/utils'
import { adminUserLogin } from '../../services/AuthService'

const Login = () => {
    const [formData, setFormData] = useState({ email: "", password: "", visibility: false });
    const [errors, setErrors] = useState({});
    const [errorMessage, setErrorMessage] = useState("")
    const navigate = useNavigate()

    const handleInputChange = (event) => {
        setFormData((inputField) => ({ ...inputField, [event.target.name]: event.target.value?.trim() }));
    }

    const handleVisibility = () => {
        setFormData((inputField) => ({ ...inputField, visibility: !formData?.visibility}));
    }

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;

        if (!formData?.email) {
            errors['email'] = "Please enter your email ID"
            formIsValid = false;
        }
        if (formData?.email && !validateEmail(formData?.email)) {
            errors['email'] = "Please enter a valid email"
            formIsValid = false;
        }
        if (!formData?.password) {
            errors['password'] = "Please enter password"
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);

        return formIsValid;
    };

    const handleLogin = async(event) => {
        console.log('call')
        event.preventDefault();
        if(validateForm()){
            let postData = {
                username: formData?.email,
                password: formData?.password
            }

            let response = await adminUserLogin(postData);
            if(response?.message === "Success!"){
                localStorage.setItem('userData', JSON.stringify(response?.body?.user));
                localStorage.setItem('userToken', JSON.stringify(response?.body?.userToken));
                localStorage.setItem('refreshToken', JSON.stringify(response?.body?.refreshToken));
                navigate('/dashboard')
            }
            if(response?.status === "401 UNAUTHORIZED" || response?.status === "404 NOT_FOUND"){
                setErrorMessage(response?.message);
            }
            setTimeout(() => {
                setErrorMessage("");
            },2000)
        }
    }


    return (
        <div className="bg-light min-vh-100 d-flex flex-row align-items-center">
            <CContainer>
                <CRow className="justify-content-center">
                    <CCol md={4}>
                        <CCardGroup>
                            <CCard className="p-4">
                                <CCardBody>
                                    <CForm>
                                        <h1>Login</h1>
                                        <p className="text-medium-emphasis">Sign In to your account</p>
                                        <CInputGroup className="mb-3">
                                            <CInputGroupText><CIcon icon={cilUser} /></CInputGroupText>
                                            <CFormInput  placeholder="Email" autoComplete="email" name="email" onChange={handleInputChange}/>
                                        </CInputGroup>
                                        {errors['email'] && <span style={{ color: "red" }}>{errors['email']}</span>}
                                        <CInputGroup className="mb-3">
                                            <CInputGroupText> <CIcon icon={cilLockLocked} /></CInputGroupText>
                                            <CFormInput type={formData?.visibility ? "text" : "password"}  placeholder="Password" autoComplete="current-password" name="password" onChange={handleInputChange}/>
                                            <CInputGroupText style={{ cursor: "pointer" }} onClick={() => { handleVisibility() }}><i class={formData?.visibility ? "fa-regular fa-eye" : "fa-solid fa-eye-slash"}></i></CInputGroupText>
                                        </CInputGroup>
                                        {errors['password'] && <span style={{ color: "red" }}>{errors['password']}</span>}
                                        {errorMessage && <span className='login-feedback-error mt-2'>{errorMessage}</span>}
                                        <div className='form-group mb-3 mt-2'>
                                        </div>
                                        <CRow>
                                            <CCol xs={6}>
                                                <CButton color="primary" className="px-4" onClick={handleLogin}> Login </CButton>
                                            </CCol>
                                            <CCol xs={6} className="text-right">
                                                <CButton color="link" className="px-0">Forgot password? </CButton>
                                            </CCol>
                                        </CRow>
                                    </CForm>
                                </CCardBody>
                            </CCard>
                        </CCardGroup>
                    </CCol>
                </CRow>
            </CContainer>
        </div>
    )
}
export default Login;
